class BatchProcessor{constructor(options={}){const defaults={data:[],asyncFunc:null,executeParallel:true};this.options={...defaults,...options};this.validateBatchProcessing()}process(){return new Promise(((resolve,reject)=>{try{if(this.options.executeParallel){this.processInParallel().then(resolve).catch(reject)}else{this.processSequentially().then(resolve).catch(reject)}}catch(e){reject(e)}}))}validateBatchProcessing(){const{data:data,asyncFunc:asyncFunc}=this.options;if(!data){throw new Error("Batch processing data cannot be null")}if(data.length<=0){throw new Error("Batch processing data cannot be empty")}if(typeof asyncFunc!=="function"){throw new Error("AsyncFunc must be a function")}}processInParallel(){const{data:data,asyncFunc:asyncFunc}=this.options;const promises=data.map((item=>asyncFunc(item)));return Promise.all(promises).then((data=>data)).catch((e=>{console.error("An error occured while processing batches in parallel: "+e);throw e}))}async processSequentially(){const{data:data,asyncFunc:asyncFunc}=this.options;const responses=[];for(let item of data){try{responses.push(await asyncFunc(item))}catch(e){console.error("An error occured while processing batches in sequential: "+e);throw e}}return responses}}